fn with_db(pool: PgPool) -> impl Filter<Extract = (PgPool,), Error = std::convert::Infallible> + Clone {
    warp::any().map(move || pool.clone())
}

async fn list_users(pool: PgPool) -> Result<impl warp::Reply, warp::Rejection> {
    let users = sqlx::query_as!(User, "SELECT * FROM users")
        .fetch_all(&pool).await.map_err(|_| warp::reject::not_found())?;
    Ok(warp::reply::json(&users))
}

