#[tokio::test]
async fn test_list_users() {
    let pool = setup_test_db().await;
    let filter = users_filter(pool);

    let resp = warp::test::request()
        .method("GET")
        .path("/api/users")
        .reply(&filter)
        .await;

    assert_eq!(resp.status(), 200);
    let body: Vec<User> = serde_json::from_slice(resp.body()).unwrap();
    assert!(!body.is_empty());
}

